1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	const BLOCK_SIZE = 3;
15	const BLOCK_PREMIUM = 60;
16	
17	function countByType(items: any[]): Record<string, number> {
18	  const counts: Record<string, number> = {};
19	  for (const item of items) {
20	    counts[item.type] = (counts[item.type] ?? 0) + 1;
21	  }
22	  return counts;
23	}
24	
25	function calculateBasePremium(typeCounts: Record<string, number>): number {
26	  let total = 0;
27	  for (const [type, count] of Object.entries(typeCounts)) {
28	    if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
29	      total += BLOCK_PREMIUM;
30	    } else {
31	      total += count * (BASE_PREMIUM[type] ?? 0);
32	    }
33	  }
34	  return total;
35	}
36	
37	const CURSED_SURCHARGE_RATE = 0.5;
38	const ENCHANTMENT_SURCHARGE_RATE = 0.3;
39	const ENCHANTMENT_THRESHOLD = 5;
40	
41	function calculateItemSurcharges(items: any[]): number {
42	  let total = 0;
43	  for (const item of items) {
44	    const base = BASE_PREMIUM[item.type] ?? 0;
45	    if (item.cursed) {
46	      total += base * CURSED_SURCHARGE_RATE;
47	    }
48	    if ((item.enchantment ?? 0) >= ENCHANTMENT_THRESHOLD) {
49	      total += base * ENCHANTMENT_SURCHARGE_RATE;
50	    }
51	  }
52	  return total;
53	}
54	
55	const LOYALTY_DISCOUNT_RATE = 0.2;
56	const LOYALTY_THRESHOLD_YEARS = 2;
57	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
58	
59	function calculateQuotePremium(items: any[], customer: any, quoteIndex: number): number {
60	  const typeCounts = countByType(items);
61	  const basePremium = calculateBasePremium(typeCounts);
62	  const itemSurcharges = calculateItemSurcharges(items);
63	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
64	  const loyaltyDiscount = (customer.yearsWithMHPCO ?? 0) >= LOYALTY_THRESHOLD_YEARS
65	    ? basePremium * LOYALTY_DISCOUNT_RATE
66	    : 0;
67	  const followUpDiscount = quoteIndex >= 1
68	    ? basePremium * FOLLOW_UP_DISCOUNT_RATE
69	    : 0;
70	  return Math.ceil(basePremium + itemSurcharges - loyaltyDiscount + firstInsurance - followUpDiscount + PROCESSING_FEE);
71	}
72	
73	const INSURANCE_VALUE: Record<string, number> = {
74	  sword: 1000,
75	  amulet: 600,
76	  staff: 800,
77	  potion: 400,
78	  rune: 250,
79	  moonstone: 250,
80	};
81	
82	const DEDUCTIBLE = 100;
83	const CAP_MULTIPLIER = 2;
84	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
85	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
86	
87	function calculateInsuranceSum(items: any[]): number {
88	  return items.reduce(
89	    (sum: number, item: any) => sum + (INSURANCE_VALUE[item.type] ?? 0),
90	    0
91	  );
92	}
93	
94	function calculateDamageReimbursement(damage: any, policyItems: any[]): number {
95	  const policyItem = policyItems.find((item: any) => item.type === damage.itemType);
96	  const enchantment = policyItem?.enchantment ?? 0;
97	  const reimbursement = enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
98	    ? damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
99	    : damage.amount;
100	  return reimbursement - DEDUCTIBLE;
101	}
102	
103	function calculateClaimResult(policy: any, incident: any): { payout: number; remainingCap: number } {
104	  const insuranceSum = calculateInsuranceSum(policy.items);
105	  const cap = insuranceSum * CAP_MULTIPLIER;
106	  const totalPayout = Math.floor(
107	    incident.damages.reduce(
108	      (sum: number, damage: any) => sum + calculateDamageReimbursement(damage, policy.items),
109	      0
110	    )
111	  );
112	  const remainingCap = cap - totalPayout;
113	  return { payout: totalPayout, remainingCap };
114	}
115	
116	export function processScenario(scenario: any): unknown {
117	  const policies: any[] = [];
118	  const results: any[] = [];
119	  let quoteIndex = 0;
120	
121	  for (const step of scenario.steps) {
122	    if (step.op === "claim") {
123	      const policy = policies[step.policy];
124	      results.push(calculateClaimResult(policy, step.incident));
125	    } else {
126	      policies.push({ items: step.items });
127	      results.push({
128	        premium: calculateQuotePremium(step.items, scenario.customer, quoteIndex),
129	      });
130	      quoteIndex++;
131	    }
132	  }
133	
134	  return { results };
135	}
